mapper.sql:
where is_deleted = 0
  and deleted_flag = 0

    and notice_id = #{noticeId}


    and recipient_user_id = #{recipientUserId}


    and read_status = #{readStatus}

mapper.select:
select 
from notice_recipient
where notice_id = #{noticeId}
  and recipient_user_id = #{recipientUserId}
limit 1

select count(1)
from notice_recipient nr
inner join notice_message nm on nm.id = nr.notice_id
where nr.is_deleted = 0
  and nr.deleted_flag = 0
  and nm.is_deleted = 0
  and nr.recipient_user_id = #{recipientUserId}

    and nr.read_status = #{readStatus}


    and nm.notice_type = #{noticeType}


    and nm.title like concat('%', #{title}, '%')

select nr.id as recipient_id, nr.notice_id, nr.recipient_user_id, nr.read_status, nr.read_at, nr.created_at as recipient_created_at, nm.notice_type, nm.title, nm.content, nm.sender_user_id, nm.biz_type, nm.biz_id, nm.channel_type, nm.priority_level, nm.publish_status, nm.send_at, nm.expire_at, coalesce(nr.remark, nm.remark) as remark from notice_recipient nr inner join notice_message nm on nm.id = nr.notice_id where nr.is_deleted = 0 and nr.deleted_flag = 0 and nm.is_deleted = 0 and nr.recipient_user_id = #{recipientUserId}
and nr.read_status = #{readStatus}
and nm.notice_type = #{noticeType}
and nm.title like concat('%', #{title}, '%')
order by case when nr.read_status = 0 then 0 else 1 end asc, nr.id desc limit #{offset}, #{size}
